Source code in <code>src/MCDE2409_parallel.py</code> <pre><code>class Nspace():

    def __init__(self,d1,d3):
        self.d1=d1
        self.d3=d3

    def v(self,n):
        if n&gt;=len(self.d1):
            return self.d3[n-len(self.d1)]
        return self.d1[n]

    def stats(self):
        print("1-particle length: "+str(len(self.d1)))
        print("3-particle length: "+str(len(self.d3)))
        print("total length: "+str(len(self.d1)+len(self.d3)))

    def translateToAOLabels(self,n,ao_labels):
        vec=self.v(n)
        if isinstance(vec,np.ndarray):
            a=ao_labels[vec[0]]
            b=ao_labels[vec[1]]
            c=ao_labels[vec[2]]

            return "{"+a+", "+b+", "+c+"}"
        return ao_labels[vec]

    def returnNumLabels(self,n):
        vec=self.v(n)
        if isinstance(vec,np.ndarray):
            a=str(vec[0])
            b=str(vec[1])
            c=str(vec[2])

            return "{"+a+", "+b+", "+c+"}"
        return str(vec)
