                                    nu2 += 1 if (spinnu == 1) else 0
                                    la2 += 1 if (spinla == 1) else 0
                                    si2 += 1 if (spinsi == 1) else 0

                                    spinmatch1 = 0.0
                                    spinmatch2 = 0.0
